#[test]
fn render_summary_matches_page_summary() {
    let from_file: OidcSystemBrowserBetaRenderSummary = load("render_summary.json");
    let page: OidcSystemBrowserBetaPage = load("page.json");
    let from_page = OidcSystemBrowserBetaRenderSummary::from_page(&page);
    assert_eq!(from_file, from_page);
}
